// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>
#define MAX_N 30
#define MAX_M 200
#define MAX_COLORS 4

// Function to check if it is safe to color a node with a given color
int is_safe(int graph[][MAX_N], int color[], int node, int c) {
    for (int i = 0; i < MAX_N; i++) {
        if (graph[node][i] && color[i] == c) {
            return 0;
        }
    }
    return 1;
}

// Function to solve the graph coloring problem using backtracking
int solve_graph_coloring(int graph[][MAX_N], int color[], int m, int n) {
    if (m == n) {
        return 1;
    }

    for (int c = 1; c <= MAX_COLORS; c++) {
        if (is_safe(graph, color, m, c)) {
            color[m] = c;
            if (solve_graph_coloring(graph, color, m + 1, n)) {
                return 1;
            }
            color[m] = 0;
        }
    }

    return 0;
}

int main() {
    int t;
    scanf("%d", &t);

    while (t--) {
        int n, m;
        scanf("%d %d", &n, &m);

        int graph[MAX_N][MAX_N] = {{0}};
        int color[MAX_N] = {0};

        for (int i = 0; i < m; i++) {
            int u, v;
            scanf("%d %d", &u, &v);
            graph[u - 1][v - 1] = graph[v - 1][u - 1] = 1;
        }

        if (solve_graph_coloring(graph, color, 0, n)) {
            printf("1\n");
        } else {
            printf("0\n");
        }
    }

    return 0;
}

